package com.example.orders.controller;

import com.example.orders.dto.OrderResponse;
import com.example.orders.exception.AccessDeniedException;
import com.example.orders.exception.OrderNotFoundException;
import com.example.orders.model.Order;
import com.example.orders.model.UserPrincipal;
import com.example.orders.service.OrderService;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/orders")
public class OrderController {

    private final OrderService orderService;
    private final AuthorizationService authorizationService;

    public OrderController(OrderService orderService, AuthorizationService authorizationService) {
        this.orderService = orderService;
        this.authorizationService = authorizationService;
    }

    @GetMapping("/{orderId}")
    public ResponseEntity<OrderResponse> getOrderById(@PathVariable Long orderId) {
        UserPrincipal currentUser = getCurrentUser();

        // Role-based authorization check
        authorizationService.assertHasRole(currentUser, "ROLE_ORDER_VIEWER", "ROLE_ADMIN", "ROLE_ORDER_MANAGER");

        Order order = orderService.findById(orderId)
                .orElseThrow(() -> new OrderNotFoundException("Order not found with id: " + orderId));

        // Tenant-level authorization: ensure user belongs to the same tenant
        authorizationService.assertSameTenant(currentUser, order.getTenantId());

        // Resource-level authorization: ensure user owns the order or has elevated role
        authorizationService.assertCanAccessOrder(currentUser, order);

        // Field-level filtering based on role
        OrderResponse response = buildAuthorizedResponse(currentUser, order);

        return ResponseEntity.ok(response);
    }

    private UserPrincipal getCurrentUser() {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated()) {
            throw new AccessDeniedException("User is not authenticated");
        }
        return (UserPrincipal) authentication.getPrincipal();
    }

    private OrderResponse buildAuthorizedResponse(UserPrincipal user, Order order) {
        OrderResponse.OrderResponseBuilder builder = OrderResponse.builder()
                .orderId(order.getId())
                .status(order.getStatus())
                .createdAt(order.getCreatedAt())
                .items(order.getItems());

        // Only managers and admins can see internal notes and cost breakdown
        if (authorizationService.hasAnyRole(user, "ROLE_ADMIN", "ROLE_ORDER_MANAGER")) {
            builder.internalNotes(order.getInternalNotes())
                    .costBreakdown(order.getCostBreakdown())
                    .assignedAgent(order.getAssignedAgent());
        }

        // Only admins can see audit trail and profit margin
        if (authorizationService.hasAnyRole(user, "ROLE_ADMIN")) {
            builder.auditTrail(order.getAuditTrail())
                    .profitMargin(order.getProfitMargin());
        }

        return builder.build();
    }
}